const therapistResponses = {
  anxiety: [
    "It sounds like you’re feeling overwhelmed. Let’s slow things down together. What’s causing the most stress right now?",
    "Anxiety can be exhausting. You’re not weak for feeling this way."
  ],
  sadness: [
    "I’m really glad you shared this. Feeling lonely can be painful, but you don’t have to face it alone.",
    "Your feelings matter. What do you think has been weighing on you lately?"
  ],
  anger: [
    "It sounds frustrating. Anger often hides deeper feelings. Would you like to explore what’s underneath it?",
    "It’s okay to feel angry. Let’s find a safe way to release it."
  ],
  happiness: [
    "I’m glad to hear that 😊 What’s been going well for you?",
    "That’s wonderful. How can we help keep this positive feeling going?"
  ],
  neutral: [
    "I’m here with you. Take your time — what’s been on your mind lately?",
    "Would you like to tell me a little more about how today has been?"
  ],
};

export default therapistResponses;
